  /// A list of visual custom actions for the analysis.
  final VisualCustomActionDefaults? customActionDefaults;

  /// A list of dataset ARNS to exclude from Dashboard Q&A.
  final List<String>? excludedDataSetArns;

  /// Determines whether insight summaries from Amazon Q Business are allowed in
  /// Dashboard Q&A.
  final QBusinessInsightsStatus? qBusinessInsightsStatus;

  /// Determines the timezone for the analysis.
  final String? timezone;

  /// Determines the week start day for an analysis.
  final DayOfTheWeek? weekStart;

  AssetOptions({
    this.customActionDefaults,
    this.excludedDataSetArns,
    this.qBusinessInsightsStatus,
    this.timezone,
    this.weekStart,
  });

  factory AssetOptions.fromJson(Map<String, dynamic> json) {
    return AssetOptions(
      customActionDefaults: json['CustomActionDefaults'] != null
          ? VisualCustomActionDefaults.fromJson(
              json['CustomActionDefaults'] as Map<String, dynamic>)
          : null,
      excludedDataSetArns: (json['ExcludedDataSetArns'] as List?)
          ?.nonNulls
          .map((e) => e as String)
          .toList(),
      qBusinessInsightsStatus: (json['QBusinessInsightsStatus'] as String?)
          ?.let(QBusinessInsightsStatus.fromString),
      timezone: json['Timezone'] as String?,
      weekStart: (json['WeekStart'] as String?)?.let(DayOfTheWeek.fromString),
    );
  }

  Map<String, dynamic> toJson() {
    final customActionDefaults = this.customActionDefaults;
    final excludedDataSetArns = this.excludedDataSetArns;
    final qBusinessInsightsStatus = this.qBusinessInsightsStatus;
    final timezone = this.timezone;
    final weekStart = this.weekStart;
    return {
      if (customActionDefaults != null)
        'CustomActionDefaults': customActionDefaults,
      if (excludedDataSetArns != null)
        'ExcludedDataSetArns': excludedDataSetArns,
      if (qBusinessInsightsStatus != null)
        'QBusinessInsightsStatus': qBusinessInsightsStatus.value,
      if (timezone != null) 'Timezone': timezone,
      if (weekStart != null) 'WeekStart': weekStart.value,
    };
  }
}

