/// Decal settings for accessibility features that define visual patterns and
/// styling for data elements.
///
/// @nodoc
class DecalSettings {
  /// Color configuration for the decal pattern.
  final String? decalColor;

  /// Type of pattern used for the decal, such as solid, diagonal, or circular
  /// patterns in various sizes.
  ///
  /// <ul>
  /// <li>
  /// <code>SOLID</code>: Solid fill pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_SMALL</code>: Small diagonal stripes pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_MEDIUM</code>: Medium diagonal stripes pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_LARGE</code>: Large diagonal stripes pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_OPPOSITE_SMALL</code>: Small cross-diagonal stripes pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_OPPOSITE_MEDIUM</code>: Medium cross-diagonal stripes
  /// pattern.
  /// </li>
  /// <li>
  /// <code>DIAGONAL_OPPOSITE_LARGE</code>: Large cross-diagonal stripes pattern.
  /// </li>
  /// <li>
  /// <code>CIRCLE_SMALL</code>: Small circle pattern.
  /// </li>
  /// <li>
  /// <code>CIRCLE_MEDIUM</code>: Medium circle pattern.
  /// </li>
  /// <li>
  /// <code>CIRCLE_LARGE</code>: Large circle pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_SMALL</code>: Small diamonds pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_MEDIUM</code>: Medium diamonds pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_LARGE</code>: Large diamonds pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_GRID_SMALL</code>: Small diamond grid pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_GRID_MEDIUM</code>: Medium diamond grid pattern.
  /// </li>
  /// <li>
  /// <code>DIAMOND_GRID_LARGE</code>: Large diamond grid pattern.
  /// </li>
  /// <li>
  /// <code>CHECKERBOARD_SMALL</code>: Small checkerboard pattern.
  /// </li>
  /// <li>
  /// <code>CHECKERBOARD_MEDIUM</code>: Medium checkerboard pattern.
  /// </li>
  /// <li>
  /// <code>CHECKERBOARD_LARGE</code>: Large checkerboard pattern.
  /// </li>
  /// <li>
  /// <code>TRIANGLE_SMALL</code>: Small triangles pattern.
  /// </li>
  /// <li>
  /// <code>TRIANGLE_MEDIUM</code>: Medium triangles pattern.
  /// </li>
  /// <li>
  /// <code>TRIANGLE_LARGE</code>: Large triangles pattern.
  /// </li>
  /// </ul>
  final DecalPatternType? decalPatternType;

  /// Style type for the decal, which can be either manual or automatic. This
  /// field is only applicable for line series.
  ///
  /// <ul>
  /// <li>
  /// <code>Manual</code>: Apply manual line and marker configuration for line
  /// series.
  /// </li>
  /// <li>
  /// <code>Auto</code>: Apply automatic line and marker configuration for line
  /// series.
  /// </li>
  /// </ul>
  final DecalStyleType? decalStyleType;

  /// Visibility setting for the decal pattern.
  final Visibility? decalVisibility;

  /// Field value of the field that you are setting the decal pattern to.
  /// Applicable only for field level settings.
  final String? elementValue;

  DecalSettings({
    this.decalColor,
    this.decalPatternType,
    this.decalStyleType,
    this.decalVisibility,
    this.elementValue,
  });

  factory DecalSettings.fromJson(Map<String, dynamic> json) {
    return DecalSettings(
      decalColor: json['DecalColor'] as String?,
      decalPatternType: (json['DecalPatternType'] as String?)
          ?.let(DecalPatternType.fromString),
      decalStyleType:
          (json['DecalStyleType'] as String?)?.let(DecalStyleType.fromString),
      decalVisibility:
          (json['DecalVisibility'] as String?)?.let(Visibility.fromString),
      elementValue: json['ElementValue'] as String?,
    );
  }

  Map<String, dynamic> toJson() {
    final decalColor = this.decalColor;
    final decalPatternType = this.decalPatternType;
    final decalStyleType = this.decalStyleType;
    final decalVisibility = this.decalVisibility;
    final elementValue = this.elementValue;
    return {
      if (decalColor != null) 'DecalColor': decalColor,
      if (decalPatternType != null) 'DecalPatternType': decalPatternType.value,
      if (decalStyleType != null) 'DecalStyleType': decalStyleType.value,
      if (decalVisibility != null) 'DecalVisibility': decalVisibility.value,
      if (elementValue != null) 'ElementValue': elementValue,
    };
  }
}

