/// @nodoc
class CommitMode {
  static const auto = CommitMode._('AUTO');
  static const manual = CommitMode._('MANUAL');

  final String value;

  const CommitMode._(this.value);

  static const values = [auto, manual];

  static CommitMode fromString(String value) => values
      .firstWhere((e) => e.value == value, orElse: () => CommitMode._(value));

  @override
  bool operator ==(other) => other is CommitMode && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

