/// @nodoc
class GeospatialColorState {
  static const enabled = GeospatialColorState._('ENABLED');
  static const disabled = GeospatialColorState._('DISABLED');

  final String value;

  const GeospatialColorState._(this.value);

  static const values = [enabled, disabled];

  static GeospatialColorState fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => GeospatialColorState._(value));

  @override
  bool operator ==(other) =>
      other is GeospatialColorState && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

