/// @nodoc
class SparklineAxisBehavior {
  static const shared = SparklineAxisBehavior._('SHARED');
  static const independent = SparklineAxisBehavior._('INDEPENDENT');

  final String value;

  const SparklineAxisBehavior._(this.value);

  static const values = [shared, independent];

  static SparklineAxisBehavior fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => SparklineAxisBehavior._(value));

  @override
  bool operator ==(other) =>
      other is SparklineAxisBehavior && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

/// @nodoc
class SparklineVisualType {
  static const line = SparklineVisualType._('LINE');
