/// The column option of the transposed table.
///
/// @nodoc
class TransposedTableOption {
  /// The column type of the column in a transposed table. Choose one of the
  /// following options:
  ///
  /// <ul>
  /// <li>
  /// <code>ROW_HEADER_COLUMN</code>: Refers to the leftmost column of the row
  /// header in the transposed table.
  /// </li>
  /// <li>
  /// <code>VALUE_COLUMN</code>: Refers to all value columns in the transposed
  /// table.
  /// </li>
  /// </ul>
  final TransposedColumnType columnType;

  /// The index of a columns in a transposed table. The index range is 0-9999.
  final int? columnIndex;

  /// The width of a column in a transposed table.
  final String? columnWidth;

  TransposedTableOption({
    required this.columnType,
    this.columnIndex,
