/// @nodoc
class CapabilityState {
  static const deny = CapabilityState._('DENY');

  final String value;

  const CapabilityState._(this.value);

  static const values = [deny];

  static CapabilityState fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => CapabilityState._(value));

  @override
  bool operator ==(other) => other is CapabilityState && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

/// The details of the brand.
///
/// @nodoc
class BrandDetail {
  /// The ID of the Quick brand.
  final String brandId;

  /// The Amazon Resource Name (ARN) of the brand.
  final String? arn;

  /// The status of the brand.
  final BrandStatus? brandStatus;

  /// The time that the brand was created.
  final DateTime? createdTime;

  /// A list of errors that occurred during the most recent brand operation.
  final List<String>? errors;

  /// The last time the brand was updated.
  final DateTime? lastUpdatedTime;

  /// The logo details.
  final Logo? logo;

  /// The ID of the version.
  final String? versionId;

  /// The status of the version.
  final BrandVersionStatus? versionStatus;

  BrandDetail({
    required this.brandId,
    this.arn,
    this.brandStatus,
    this.createdTime,
    this.errors,
    this.lastUpdatedTime,
    this.logo,
    this.versionId,
    this.versionStatus,
  });

  factory BrandDetail.fromJson(Map<String, dynamic> json) {
    return BrandDetail(
      brandId: (json['BrandId'] as String?) ?? '',
      arn: json['Arn'] as String?,
      brandStatus:
          (json['BrandStatus'] as String?)?.let(BrandStatus.fromString),
      createdTime: timeStampFromJson(json['CreatedTime']),
      errors:
          (json['Errors'] as List?)?.nonNulls.map((e) => e as String).toList(),
      lastUpdatedTime: timeStampFromJson(json['LastUpdatedTime']),
      logo: json['Logo'] != null
          ? Logo.fromJson(json['Logo'] as Map<String, dynamic>)
          : null,
      versionId: json['VersionId'] as String?,
      versionStatus: (json['VersionStatus'] as String?)
          ?.let(BrandVersionStatus.fromString),
    );
  }

  Map<String, dynamic> toJson() {
    final brandId = this.brandId;
    final arn = this.arn;
    final brandStatus = this.brandStatus;
    final createdTime = this.createdTime;
    final errors = this.errors;
    final lastUpdatedTime = this.lastUpdatedTime;
    final logo = this.logo;
    final versionId = this.versionId;
    final versionStatus = this.versionStatus;
    return {
      'BrandId': brandId,
      if (arn != null) 'Arn': arn,
      if (brandStatus != null) 'BrandStatus': brandStatus.value,
      if (createdTime != null) 'CreatedTime': unixTimestampToJson(createdTime),
      if (errors != null) 'Errors': errors,
      if (lastUpdatedTime != null)
        'LastUpdatedTime': unixTimestampToJson(lastUpdatedTime),
      if (logo != null) 'Logo': logo,
      if (versionId != null) 'VersionId': versionId,
      if (versionStatus != null) 'VersionStatus': versionStatus.value,
    };
  }
}

