  /// The display name of the flow.
  final String name;

  /// The identifier of the principal who created the flow.
  final String? createdBy;

  /// The description of the flow.
  final String? description;

  /// The last time this flow was published.
  final DateTime? lastPublishedAt;

  /// The identifier of the last principal who published the flow.
  final String? lastPublishedBy;

  /// The identifier of the last principal who updated the flow.
  final String? lastUpdatedBy;

  /// The last time this flow was modified.
  final DateTime? lastUpdatedTime;

  /// The publish state for the flow. The valid values are <code>DRAFT</code>,
  /// <code>PUBLISHED</code>, or <code>PENDING_APPROVAL</code>.
  final FlowPublishState? publishState;

  /// The number of runs done for the flow.
  final int? runCount;

  /// The number of users who have used the flow.
  final int? userCount;

  FlowSummary({
    required this.arn,
    required this.createdTime,
    required this.flowId,
    required this.name,
    this.createdBy,
    this.description,
    this.lastPublishedAt,
    this.lastPublishedBy,
    this.lastUpdatedBy,
    this.lastUpdatedTime,
    this.publishState,
    this.runCount,
    this.userCount,
  });

  factory FlowSummary.fromJson(Map<String, dynamic> json) {
    return FlowSummary(
      arn: (json['Arn'] as String?) ?? '',
      createdTime: nonNullableTimeStampFromJson(json['CreatedTime'] ?? 0),
      flowId: (json['FlowId'] as String?) ?? '',
      name: (json['Name'] as String?) ?? '',
      createdBy: json['CreatedBy'] as String?,
      description: json['Description'] as String?,
      lastPublishedAt: timeStampFromJson(json['LastPublishedAt']),
      lastPublishedBy: json['LastPublishedBy'] as String?,
      lastUpdatedBy: json['LastUpdatedBy'] as String?,
      lastUpdatedTime: timeStampFromJson(json['LastUpdatedTime']),
      publishState:
          (json['PublishState'] as String?)?.let(FlowPublishState.fromString),
      runCount: json['RunCount'] as int?,
      userCount: json['UserCount'] as int?,
    );
  }

  Map<String, dynamic> toJson() {
    final arn = this.arn;
    final createdTime = this.createdTime;
    final flowId = this.flowId;
    final name = this.name;
    final createdBy = this.createdBy;
    final description = this.description;
    final lastPublishedAt = this.lastPublishedAt;
    final lastPublishedBy = this.lastPublishedBy;
    final lastUpdatedBy = this.lastUpdatedBy;
    final lastUpdatedTime = this.lastUpdatedTime;
    final publishState = this.publishState;
    final runCount = this.runCount;
    final userCount = this.userCount;
    return {
      'Arn': arn,
      'CreatedTime': unixTimestampToJson(createdTime),
      'FlowId': flowId,
      'Name': name,
      if (createdBy != null) 'CreatedBy': createdBy,
      if (description != null) 'Description': description,
      if (lastPublishedAt != null)
        'LastPublishedAt': unixTimestampToJson(lastPublishedAt),
      if (lastPublishedBy != null) 'LastPublishedBy': lastPublishedBy,
      if (lastUpdatedBy != null) 'LastUpdatedBy': lastUpdatedBy,
      if (lastUpdatedTime != null)
        'LastUpdatedTime': unixTimestampToJson(lastUpdatedTime),
      if (publishState != null) 'PublishState': publishState.value,
      if (runCount != null) 'RunCount': runCount,
      if (userCount != null) 'UserCount': userCount,
    };
  }
}

