/// @nodoc
class KbIngestionStatus {
  static const queued = KbIngestionStatus._('QUEUED');
  static const running = KbIngestionStatus._('RUNNING');
  static const failed = KbIngestionStatus._('FAILED');
  static const completed = KbIngestionStatus._('COMPLETED');
  static const incomplete = KbIngestionStatus._('INCOMPLETE');
  static const cancelled = KbIngestionStatus._('CANCELLED');
  static const cancelling = KbIngestionStatus._('CANCELLING');
  static const timeout = KbIngestionStatus._('TIMEOUT');

  final String value;

  const KbIngestionStatus._(this.value);

  static const values = [
    queued,
    running,
    failed,
    completed,
    incomplete,
    cancelled,
    cancelling,
    timeout
  ];

  static KbIngestionStatus fromString(String value) =>
      values.firstWhere((e) => e.value == value,
          orElse: () => KbIngestionStatus._(value));

  @override
  bool operator ==(other) => other is KbIngestionStatus && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

